export const leadershipTopics = [
  { topic: "Team Leadership", questions: ["How do you build psychological safety?", "How do you run 1:1s effectively?", "How do you set team goals?"], tips: "Show you lead by example, create safety to fail, give clear expectations and autonomy simultaneously." },
  { topic: "Handling Underperformers", questions: ["An engineer is consistently missing deadlines — what do you do?", "When do you put someone on a PIP?", "Tell me about a time you had to let someone go."], tips: "Early intervention. Specific feedback. Clear expectations. Document. Support. Know when to escalate to HR. Show compassion AND accountability." },
  { topic: "Mentoring Engineers", questions: ["How do you mentor a senior engineer?", "How do you accelerate a new grad's growth?", "Tell me about someone you grew significantly."], tips: "Tailored approach per individual. Stretch assignments. Sponsorship vs mentorship distinction. Feedback cadence. Clear career path discussions." },
  { topic: "Technical Decision Making", questions: ["How do you make build vs buy decisions?", "How do you choose between two architectural approaches?", "Tell me about a major technical decision you made."], tips: "Show structured decision process: options → tradeoffs → decision → communication. Use ADRs. Involve team. Show ownership of outcome." },
  { topic: "Hiring & Interview Bar", questions: ["How do you hire great engineers?", "How do you avoid bias in interviews?", "What's your bar for senior engineer vs staff?"], tips: "Structured interviews. Rubrics. Calibration sessions. Diverse sourcing. Removing bias (blind resumes, structured questions). Know your level ladder." },
  { topic: "Conflict Resolution", questions: ["Two senior engineers disagree on architecture — how do you handle it?", "A PM and your team have conflicting priorities — what do you do?"], tips: "Listen first. Separate positions from interests. Find common ground. Be the last to speak. Escalate with options, not problems. Know when to decide vs facilitate." }
];

