// Design pattern challenges (GoF + interview-favorite enterprise patterns).
// Common at corporate IT/consulting interviews (Accenture, Capgemini, TCS, EPAM)
// and at all FAANG mid-level loops. Same ChallengeItem schema.
export const patternsChallenges = [
  { id: 70001, lang: "Pattern", diff: "easy", title: "Strategy Pattern",
    concepts: "Strategy, polymorphism, runtime dispatch, open-closed principle",
    problem: "You have a checkout system that supports CreditCard, PayPal, ApplePay, and crypto. Currently it's a giant if/else in `processPayment()`. Refactor using the Strategy pattern. Show the interface, concrete strategies, and how to add a new one without touching the checkout class.",
    why: "Strategy is the workhorse of OCP-compliant code. Every time you reach for a switch on type, ask: should this be a strategy?",
    examples: "// BEFORE — switch on type, violates Open-Closed\nif (method == 'CARD')      processCard(...)\nelse if (method == 'PAYPAL') processPayPal(...)\nelse if (method == 'CRYPTO') processCrypto(...)\n// adding ApplePay = touching this file\n\n// AFTER — Strategy\ninterface PaymentStrategy {\n  Receipt charge(BigDecimal amount, Customer c);\n}\nclass StripeStrategy implements PaymentStrategy { ... }\nclass PayPalStrategy implements PaymentStrategy { ... }\nclass CryptoStrategy implements PaymentStrategy { ... }\n\nclass Checkout {\n  private final PaymentStrategy strategy;\n  Checkout(PaymentStrategy s) { this.strategy = s; }\n  Receipt complete(Cart cart) { return strategy.charge(cart.total(), cart.customer()); }\n}\n\n// Adding ApplePay = new class only. Checkout untouched.\nMap<String, PaymentStrategy> registry = Map.of(\n  'CARD',   new StripeStrategy(),\n  'PAYPAL', new PayPalStrategy(),\n  'APPLE',  new ApplePayStrategy()\n);",
    testInputs: "Strategy vs State: Strategy is set externally, State changes itself. Strategy vs Template Method: Strategy is composition (runtime), TM is inheritance (compile-time).",
    explanation: "Strategy = swap an algorithm without touching its caller. Pair with a registry/factory for selection. Refactor smell: long if/else on a type. Anti-pattern: putting business rules in the strategy itself instead of behind a service it calls." },

  { id: 70002, lang: "Pattern", diff: "easy", title: "Factory vs Builder — When Each",
    concepts: "Factory Method, Abstract Factory, Builder, fluent API, immutability",
    problem: "When do you reach for Factory vs Builder? Show one example of each, and one case where they're combined.",
    why: "These get conflated. Factory hides creation logic; Builder steps through it. Different problems, different shapes.",
    examples: "// FACTORY — hide which subclass to construct\ninterface Connection { ... }\nclass MySqlConnection implements Connection { ... }\nclass PostgresConnection implements Connection { ... }\n\nclass ConnectionFactory {\n  static Connection from(String url) {\n    if (url.startsWith('jdbc:mysql'))    return new MySqlConnection(url);\n    if (url.startsWith('jdbc:postgres')) return new PostgresConnection(url);\n    throw new IllegalArgumentException(url);\n  }\n}\n\n// BUILDER — assemble an immutable object piece by piece\nHttpRequest req = HttpRequest.newBuilder()\n  .uri('https://api.example.com/users')\n  .header('Authorization', token)\n  .header('Accept', 'application/json')\n  .timeout(Duration.ofSeconds(5))\n  .POST(BodyPublishers.ofString(json))\n  .build();\n\n// COMBINED — Factory returns a Builder\nQuery q = QueryBuilder.from('users')   // factory selects dialect\n  .where('status', 'active')\n  .orderBy('created_at')\n  .limit(50)\n  .build();",
    testInputs: "Use Factory when caller shouldn't know the concrete type. Use Builder when constructor would have 5+ params, optional fields, or order matters. Anti-pattern: telescoping constructors (User(name), User(name, email), User(name, email, age)…).",
    explanation: "Factory hides the WHICH (subclass selection); Builder hides the HOW (step-by-step construction). They aren't competing — they often pair. Modern Java/Kotlin/Swift mostly use Builder via the language's named/default args; classic Java/C# still need it explicitly." },

  { id: 70003, lang: "Pattern", diff: "medium", title: "Singleton — Why It's an Anti-Pattern",
    concepts: "Singleton, global state, testability, hidden dependencies, DI",
    problem: "Singletons feel convenient but are often called an anti-pattern. Explain three concrete reasons, and show what to use instead.",
    why: "Every interviewer asks this. The 'correct' singleton is rarely a singleton — it's a single instance managed by a DI container.",
    examples: "// THE PROBLEMS\n// 1. Hidden dependency\nclass OrderService {\n  void place(Order o) {\n    EmailClient.getInstance().send(...);  // who knew this depended on email?\n  }\n}\n// Tests can't substitute. CI breaks if email server is down.\n\n// 2. Global mutable state\nConfig.getInstance().setMode('TEST');  // changes behavior of every other consumer\n\n// 3. Concurrency / lifecycle issues\n// Multiple class loaders → multiple singletons.\n// Lazy init + threads → famous double-checked-locking bugs.\n\n// THE FIX — dependency injection\nclass OrderService {\n  private final EmailClient email;\n  OrderService(EmailClient email) { this.email = email; }   // explicit\n  void place(Order o) { email.send(...); }\n}\n// Spring/Guice/manual: bind EmailClient as singleton-scoped. ONE instance, but injected.\n\n// LEGITIMATE singleton uses\n// - Stateless utilities (Math, Logger factory)\n// - True process-wide resources (thread pool, JDBC pool) — managed by container\n// - Enums in Java (Effective Java item 3)",
    testInputs: "Joshua Bloch's enum singleton (`enum Foo { INSTANCE; }`) is the only thread-safe, serialization-safe, reflection-safe singleton in Java. Use it if you must.",
    explanation: "Singleton-the-pattern is fine for stateless services but Singleton-as-global-mutable-state is what people complain about. The DI container gives you 'one instance, injected, swappable in tests' — same lifecycle, none of the pain. If you find yourself writing `getInstance()`, ask: what stops me from injecting this?" },

  { id: 70004, lang: "Pattern", diff: "medium", title: "Repository Pattern — Domain vs Data Boundary",
    concepts: "Repository, DDD, separation of concerns, ORM, testability",
    problem: "Show the Repository pattern in a Spring/JPA app. What boundary is it enforcing, and when is the pattern wrong (anti-pattern of 'leaky repository')?",
    why: "Repository is one of the most-asked Spring/Java patterns. Mis-applied, it just hides the ORM and adds noise; well-applied, it isolates the domain from persistence concerns.",
    examples: "// DOMAIN layer — knows nothing about JPA, JDBC, Mongo\nclass Order {\n  void cancel() { ... }   // pure business logic\n}\n\ninterface OrderRepository {\n  Optional<Order> findById(OrderId id);\n  void save(Order o);\n  List<Order> findOpenForCustomer(CustomerId c);\n}\n\n// INFRASTRUCTURE layer — implementation\nclass JpaOrderRepository implements OrderRepository {\n  private final EntityManager em;\n  public Optional<Order> findById(OrderId id) {\n    OrderEntity e = em.find(OrderEntity.class, id.value());\n    return Optional.ofNullable(e).map(this::toDomain);\n  }\n  // mapping JPA entity ↔ domain object\n}\n\n// APPLICATION SERVICE\nclass CancelOrderService {\n  private final OrderRepository repo;\n  void cancel(OrderId id) {\n    Order o = repo.findById(id).orElseThrow();\n    o.cancel();           // domain rule applied\n    repo.save(o);\n  }\n}\n\n// LEAKY ANTI-PATTERN\ninterface OrderRepository extends JpaRepository<OrderEntity, Long> { ... }\n// now app service knows JPA. Domain object IS the entity. No isolation. Just renamed DAO.",
    testInputs: "Test: substitute InMemoryOrderRepository for unit tests — no DB. Anti-pattern test: can your domain class compile without JPA on the classpath? If not, your repository is leaking.",
    explanation: "Repository = a collection-like interface for aggregates, defined IN the domain, implemented IN infrastructure. The win is testability + persistence-independence. Spring Data JpaRepository is fine for CRUD apps but is a leaky repository — domain depends on JPA. For pure DDD, hand-write the interface in domain and adapt JPA in infra." },

  { id: 70005, lang: "Pattern", diff: "easy", title: "Decorator Pattern — Adding Behavior Transparently",
    concepts: "Decorator, wrapping, cross-cutting concerns, OCP, composition",
    problem: "You have an `EmailSender` interface. Add logging, retry, and metrics WITHOUT modifying the original implementation. Show the decorator stack.",
    why: "Decorators are how you compose cross-cutting concerns without inheritance hell or AOP magic.",
    examples: "interface EmailSender {\n  void send(Email e);\n}\n\nclass SmtpEmailSender implements EmailSender {\n  public void send(Email e) { /* talk to SMTP */ }\n}\n\n// DECORATORS — each wraps the next\nclass LoggingEmailSender implements EmailSender {\n  private final EmailSender inner;\n  LoggingEmailSender(EmailSender inner) { this.inner = inner; }\n  public void send(Email e) {\n    log.info('sending {} to {}', e.subject, e.to);\n    inner.send(e);\n    log.info('sent');\n  }\n}\n\nclass RetryEmailSender implements EmailSender {\n  private final EmailSender inner;\n  public void send(Email e) {\n    for (int i = 0; i < 3; i++) {\n      try { inner.send(e); return; }\n      catch (Exception ex) { if (i == 2) throw ex; backoff(i); }\n    }\n  }\n}\n\nclass MetricsEmailSender implements EmailSender { ... }\n\n// COMPOSE — order matters\nEmailSender sender = new MetricsEmailSender(\n                       new RetryEmailSender(\n                         new LoggingEmailSender(\n                           new SmtpEmailSender())));\n// metrics outermost (so it sees retries as 1 op), retry middle, log inside, smtp innermost.\n\n// JAVA STDLIB EXAMPLE: BufferedReader(new FileReader(path))\n// — same pattern, ubiquitous in IO.",
    testInputs: "Decorator vs Proxy: Decorator adds behavior; Proxy controls access. Decorator vs Adapter: Decorator preserves the interface; Adapter changes it. Decorator vs Inheritance: Decorator wraps at runtime; inheritance is compile-time and explodes class count.",
    explanation: "Decorators let you stack orthogonal concerns. Order matters — outermost runs first on entry, last on return. Real-world: HTTP client middleware (axios interceptors, OkHttp interceptors, Express middleware) is exactly this pattern at a different name." },

  { id: 70006, lang: "Pattern", diff: "easy", title: "Adapter Pattern — Bridging Incompatible APIs",
    concepts: "Adapter, integration, legacy systems, interface translation",
    problem: "You're integrating a SOAP-based legacy CRM into your REST microservices. Show the Adapter pattern that keeps your domain code clean.",
    why: "Adapter is the most useful pattern for any 'bring legacy into a modern codebase' work. Accenture-style consulting projects live and die on it.",
    examples: "// What your domain wants\ninterface CustomerLookup {\n  Optional<Customer> byEmail(String email);\n}\n\n// What you actually have — gnarly SOAP client\nclass LegacyCrmSoapClient {\n  CrmResponse fetchCustomerByEmailAddress(SoapEnvelope env) { ... }\n}\n\n// ADAPTER\nclass LegacyCrmAdapter implements CustomerLookup {\n  private final LegacyCrmSoapClient client;\n  public Optional<Customer> byEmail(String email) {\n    SoapEnvelope env = SoapEnvelope.builder()\n      .header('LegacyAuth', token)\n      .body(\"<email>\" + email + \"</email>\")\n      .build();\n    try {\n      CrmResponse r = client.fetchCustomerByEmailAddress(env);\n      if (r.isError() && r.errorCode().equals('NOT_FOUND')) return Optional.empty();\n      return Optional.of(toDomain(r));\n    } catch (SoapFault f) {\n      throw new InfrastructureException(f);   // domain exception, not SoapFault\n    }\n  }\n  private Customer toDomain(CrmResponse r) { ... }\n}\n\n// Your services depend on CustomerLookup, never on the SOAP client.\n// Day you migrate to a new CRM: write a new adapter, swap the bean. Domain untouched.",
    testInputs: "Two-way adapter: when you also need to pass DATA from legacy back to modern. Often pairs with anti-corruption-layer (DDD): the adapter actively translates legacy concepts into your bounded-context vocabulary.",
    explanation: "Adapter = thin translation layer between two interfaces. Always include error translation (SoapFault → DomainException) so callers don't need to know what's behind the adapter. Adapter is also the easiest pattern to test — mock the underlying client, assert the translation." },

  { id: 70007, lang: "Pattern", diff: "easy", title: "Observer / Pub-Sub Pattern",
    concepts: "Observer, event-driven, pub/sub, decoupling, listeners",
    problem: "Compare the in-process Observer pattern (Java listeners, JS EventEmitter) with distributed pub/sub (Kafka, RabbitMQ, SNS). Show when to use each and where Observer breaks.",
    why: "Both are 'someone publishes, someone reacts' — but they have very different failure modes and ordering guarantees.",
    examples: "// IN-PROCESS OBSERVER\nclass OrderPlacedEvent { final OrderId id; ... }\n\nclass OrderService {\n  private final List<OrderListener> listeners = new ArrayList<>();\n  void register(OrderListener l) { listeners.add(l); }\n  void place(Order o) {\n    save(o);\n    for (var l : listeners) l.onPlaced(new OrderPlacedEvent(o.id()));\n  }\n}\n// pros: simple, transactional with the order\n// cons: synchronous, all-or-nothing, listener errors block; not durable\n\n// SPRING ApplicationEvent — same pattern, framework-managed\n@EventListener\nvoid sendConfirmationEmail(OrderPlacedEvent e) { ... }\n\n// DISTRIBUTED PUB/SUB\nproducer.send('orders.placed', json(event));\n// pros: durable (Kafka), async, multi-consumer, scales\n// cons: at-least-once delivery (consumers must be idempotent), eventual consistency,\n//       harder to debug, message versioning headaches\n\n// HYBRID — outbox pattern\n// 1. write order + event row to DB in same transaction\n// 2. CDC tail / poll publishes to Kafka\n// 3. consumers idempotently react\n// (this is the pattern when you need transactional + distributed.)",
    testInputs: "When in-process Observer is wrong: cross-service decoupling, audit logging that must survive crashes, fan-out to many independent teams. When distributed pub/sub is overkill: monolith, single team, sub-100ms reactions, no durability needs.",
    explanation: "Observer = pattern. Pub/sub = the same pattern with a durable broker between publisher and subscriber. Choose by asking: does the reaction need to survive a crash? must it scale to N consumers we don't control? if yes → pub/sub; if no → in-process events." },

  { id: 70008, lang: "Pattern", diff: "medium", title: "Command Pattern — Undo, Queueing, Audit",
    concepts: "Command, undo, redo, queue, event sourcing, CQRS",
    problem: "Implement a basic undo/redo for a text editor using the Command pattern. Then describe how the same shape powers job queues and CQRS write models.",
    why: "Command is the bridge between OOP design patterns and event-driven architectures. Same shape, different problems.",
    examples: "interface Command {\n  void execute();\n  void undo();\n}\n\nclass InsertText implements Command {\n  private final Document doc;\n  private final int pos;\n  private final String text;\n  public void execute() { doc.insert(pos, text); }\n  public void undo()    { doc.deleteRange(pos, pos + text.length()); }\n}\n\nclass Editor {\n  private final Deque<Command> undo = new ArrayDeque<>();\n  private final Deque<Command> redo = new ArrayDeque<>();\n  void do_(Command c) { c.execute(); undo.push(c); redo.clear(); }\n  void undo() { if (!undo.isEmpty()) { Command c = undo.pop(); c.undo(); redo.push(c); } }\n  void redo() { if (!redo.isEmpty()) { Command c = redo.pop(); c.execute(); undo.push(c); } }\n}\n\n// SAME SHAPE — job queue\nclass SendEmailJob implements Command { ... }\nqueue.enqueue(new SendEmailJob(...));   // serialize, persist, distribute\n\n// SAME SHAPE — CQRS write side\nclass PlaceOrderCommand { ... }\ncommandHandler.handle(new PlaceOrderCommand(...));   // validates + emits events",
    testInputs: "Undo bug: not capturing enough state in execute(). The command must remember what it changed so undo can reverse it (or store an inverse command). Composite commands: a 'paste' command is multiple insert commands grouped.",
    explanation: "Command = encapsulating a request as an object. Lets you queue, log, retry, undo, and route them. The pattern is everywhere once you see it — Redux actions, CQRS commands, RxJava operators, PostgreSQL transactions, git commits." },

  { id: 70009, lang: "Pattern", diff: "medium", title: "Chain of Responsibility — Middleware",
    concepts: "Chain of Responsibility, middleware, request handling, filters, pipeline",
    problem: "Build a request-handling pipeline (auth → rate limit → validation → handler) using Chain of Responsibility. Compare with the equivalent Express/Koa/Spring filter chain.",
    why: "Every modern web framework is Chain of Responsibility under the hood. Recognizing it makes server frameworks feel inevitable instead of magical.",
    examples: "interface Handler {\n  void handle(Request req, Response res, Handler next);\n}\n\nclass AuthHandler implements Handler {\n  public void handle(Request req, Response res, Handler next) {\n    String token = req.header('Authorization');\n    if (!validate(token)) { res.status(401); return; }\n    req.setUser(parse(token));\n    next.handle(req, res, /* next-next */);\n  }\n}\n\nclass RateLimitHandler implements Handler { ... }\nclass ValidationHandler implements Handler { ... }\nclass BusinessHandler implements Handler {\n  public void handle(Request req, Response res, Handler next) {\n    res.json(processOrder(req.body()));   // terminal — doesn't call next\n  }\n}\n\n// Build the chain\nList<Handler> chain = List.of(\n  new AuthHandler(), new RateLimitHandler(), new ValidationHandler(), new BusinessHandler()\n);\nrun(chain, req, res);   // orchestrator threads `next` through\n\n// EXPRESS\napp.use(authMiddleware);\napp.use(rateLimit);\napp.post('/orders', validate, business);\n// each middleware: (req, res, next) => { ... next(); }\n// IDENTICAL pattern, different syntax.\n\n// SPRING SECURITY\n// FilterChain: List<Filter>, each calls chain.doFilter(req, res) to advance.",
    testInputs: "Bug: middleware that forgets to call next() — request hangs forever. Bug: middleware that calls next() AND writes a response — double send. Termination convention: terminal handlers (the actual route) don't call next.",
    explanation: "Chain of Responsibility = each handler decides to handle, modify-and-pass, or short-circuit. The `next` callback is the lever. Underpins every web framework's middleware/filter API. Anti-pattern: tightly coupling handler order via business logic checks instead of explicit chain composition." },

  { id: 70010, lang: "Pattern", diff: "easy", title: "Facade Pattern — Hiding Subsystem Complexity",
    concepts: "Facade, simplification, subsystem, encapsulation",
    problem: "You're integrating an order fulfillment subsystem with 5 collaborators (inventory, pricing, payment, shipping, notification). Show how a Facade simplifies the calling code.",
    why: "Facades reduce the cognitive surface for callers. Most well-designed services are facades over deeper subsystems.",
    examples: "// WITHOUT FACADE — caller orchestrates everything\nclass CheckoutController {\n  void checkout(Cart c) {\n    InventoryReservation r = inventory.reserve(c.items());\n    Money price = pricing.compute(c.items(), c.coupons());\n    Payment p = payment.charge(c.customer(), price);\n    if (p.failed()) { inventory.release(r); throw new PaymentFailed(); }\n    Shipment s = shipping.schedule(c.address(), c.items());\n    notification.sendConfirmation(c.customer(), s);\n  }\n}\n// 5 dependencies, transactional logic leaked into the controller.\n\n// FACADE\nclass OrderFulfillment {\n  private final Inventory inv;\n  private final Pricing pricing;\n  private final Payment payment;\n  private final Shipping shipping;\n  private final Notification notification;\n\n  Order place(Cart c) {\n    InventoryReservation r = inv.reserve(c.items());\n    try {\n      Money price = pricing.compute(c.items(), c.coupons());\n      Payment p = payment.charge(c.customer(), price);\n      if (p.failed()) throw new PaymentFailed();\n      Shipment s = shipping.schedule(c.address(), c.items());\n      notification.sendConfirmation(c.customer(), s);\n      return new Order(c, p, s);\n    } catch (Exception e) {\n      inv.release(r);   // compensating action\n      throw e;\n    }\n  }\n}\n\nclass CheckoutController {\n  private final OrderFulfillment fulfillment;   // ONE dependency\n  void checkout(Cart c) { fulfillment.place(c); }\n}",
    testInputs: "Facade vs Adapter: Facade simplifies a complex subsystem (1→N hidden); Adapter translates between two interfaces (1↔1). Facade vs Service: when the orchestration crosses transactional boundaries, you've graduated to a Saga or process manager — not a simple facade.",
    explanation: "Facade = a single entry point hiding multi-step orchestration. Reduces caller dependencies and lets the subsystem evolve internally. Smell: every controller in your codebase has 6+ injected services — that's missing facades. Don't confuse 'thin wrapper' with facade — a facade actually does coordination work." },

  { id: 70011, lang: "Pattern", diff: "medium", title: "Template Method — Invariant Skeleton",
    concepts: "Template Method, inheritance, hook methods, framework design",
    problem: "Design a `ReportGenerator` base class that defines the skeleton (load → transform → render) but lets subclasses override individual steps. When is Template Method better than Strategy, and when is it worse?",
    why: "Template Method shows up in every framework — Spring, Servlet, JUnit. Recognizing it explains a lot of 'why does this base class do that' confusion.",
    examples: "abstract class ReportGenerator {\n  // TEMPLATE — final, defines the skeleton\n  public final Report generate(ReportRequest req) {\n    Data d   = loadData(req);          // hook\n    Data t   = transform(d);           // hook\n    Layout l = layout(t);              // hook\n    Output o = render(l);              // hook\n    audit(req, o);                     // shared concrete step\n    return new Report(o);\n  }\n  protected abstract Data loadData(ReportRequest req);\n  protected Data transform(Data d) { return d; }    // optional override\n  protected abstract Layout layout(Data t);\n  protected abstract Output render(Layout l);\n  private void audit(ReportRequest req, Output o) { /* shared */ }\n}\n\nclass SalesReport extends ReportGenerator {\n  protected Data loadData(ReportRequest req) { return salesDb.query(req); }\n  protected Layout layout(Data t)            { return new TableLayout(t); }\n  protected Output render(Layout l)          { return new ExcelOutput(l); }\n}\n\n// SPRING JdbcTemplate is exactly this — invariant connection/cleanup, you provide the SQL.\n// Servlet HttpServlet — invariant request handling, you override doGet/doPost.\n// JUnit TestCase — invariant setup/teardown around your test method.",
    testInputs: "Template Method (inheritance): better when there's a true skeleton + plug-in points and the variations form a closed set. Strategy (composition): better when variations change at runtime, when you need multiple strategies on one object, or when subclass explosion would happen.",
    explanation: "Template Method = define skeleton in base class, defer steps to subclasses. The Hollywood Principle: 'don't call us, we'll call you' — the framework calls your hooks. Anti-pattern: making EVERY method overridable; lock down the template so subclasses can only modify intended seams." },

  { id: 70012, lang: "Pattern", diff: "medium", title: "Specification Pattern — Composable Business Rules",
    concepts: "Specification, business rules, composition, AND/OR/NOT, predicate",
    problem: "You have business rules like 'eligible for premium discount = (active customer) AND (lifetime spend > $1000) AND (not currently in arrears)'. Implement this with the Specification pattern. Why is it better than scattering ifs?",
    why: "Specification keeps business rules composable, testable, and reusable across query and validation contexts. Common in DDD codebases.",
    examples: "interface Specification<T> {\n  boolean isSatisfiedBy(T candidate);\n  default Specification<T> and(Specification<T> other) {\n    return c -> this.isSatisfiedBy(c) && other.isSatisfiedBy(c);\n  }\n  default Specification<T> or(Specification<T> other) { ... }\n  default Specification<T> not() { ... }\n}\n\nclass IsActive implements Specification<Customer> {\n  public boolean isSatisfiedBy(Customer c) { return c.status() == ACTIVE; }\n}\nclass HasSpendOver implements Specification<Customer> {\n  private final Money threshold;\n  HasSpendOver(Money m) { this.threshold = m; }\n  public boolean isSatisfiedBy(Customer c) { return c.lifetimeSpend().gt(threshold); }\n}\nclass IsInArrears implements Specification<Customer> { ... }\n\n// COMPOSE\nSpecification<Customer> eligibleForPremium =\n  new IsActive()\n    .and(new HasSpendOver(Money.dollars(1000)))\n    .and(new IsInArrears().not());\n\n// USE — same spec works for filter AND validate\ncustomers.stream().filter(eligibleForPremium::isSatisfiedBy).toList();\nif (!eligibleForPremium.isSatisfiedBy(customer)) throw new NotEligible();\n\n// SPRING DATA SUPPORTS IT NATIVELY\nrepo.findAll(Specification.where(isActive).and(hasSpendOver(1000)));\n// — translated to JPA criteria query.",
    testInputs: "Pure functional alternative: Predicate<T> + Predicate.and/or/negate. Specification adds: explicit naming (you can ask 'why didn't this match?'), persistence translation, and DI-friendliness.",
    explanation: "Specification = a business rule as an object. Composes via and/or/not. Win: the rule has a name (`EligibleForPremium`), is testable in isolation, and can be reused across filtering, validation, query building. Often paired with Repository (`repo.findAll(spec)`) for clean filter queries that domain code can construct." },
];


